  ('judicial-cf446b4c-moex-00143', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'essay', '甲乙為好友，甲因公司外派到國外三年，乙剛好需要找屋租賃，甲將其
所有之 A屋在其出國期間借乙住，但借住期間之大樓管理費新臺幣（下
同）30000 元由乙負責，以及水電瓦斯費亦由乙自行負責，乙並幫甲照
顧甲的貓咪，照顧貓咪之相關費用由乙負責。乙住進一個月後，覺得甲
的房子蠻大，在未經甲的同意下以甲的名義，將其中一間房間租給丙，
租期直到甲回國，月租為 6000元，丙應分擔每月的水電與瓦斯費用 500
元。問甲乙丙間之法律關係如何？又甲在國外期間，乙將房間出租取得
收入若干，甲是否得向乙主張享有該出租所得之利益？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
